import jwt, { Algorithm, SignOptions, VerifyOptions, JwtPayload } from 'jsonwebtoken';

export interface JwtConfig {
  secret?: string;
  algorithm?: Algorithm; // e.g. 'HS256' | 'none'
  expiresIn?: string | number;
}

const DEFAULT_SECRET = 'secret123';
const DEFAULT_ALGORITHM: Algorithm = 'HS256';

export class AuthService {
  private readonly secret: string;
  private readonly algorithm: Algorithm;
  private readonly expiresIn?: string | number;

  constructor(config: JwtConfig = {}) {
    this.algorithm = config.algorithm ?? DEFAULT_ALGORITHM;
    this.secret = this.algorithm === 'none' ? '' : config.secret ?? DEFAULT_SECRET;
    this.expiresIn = config.expiresIn;
  }

  sign(
    payload: string | Buffer | object,
    options: Omit<SignOptions, 'algorithm'> = {}
  ): string {
    const signOptions: SignOptions = {
      algorithm: this.algorithm,
      ...(this.expiresIn ? { expiresIn: this.expiresIn } : {}),
      ...options,
    };

    return jwt.sign(payload, this.secret, signOptions);
  }

  verify<T extends string | JwtPayload = JwtPayload>(
    token: string,
    options: Omit<VerifyOptions, 'algorithms'> = {}
  ): T {
    const verifyOptions: VerifyOptions = {
      algorithms: [this.algorithm],
      ...options,
    };

    return jwt.verify(token, this.secret, verifyOptions) as T;
  }
}